import { forwardRef, useEffect, useMemo, useRef } from 'react';
import ArvoCheckbox from '../Checkbox/Checkbox';
import FilterOption, { type FilterOptionSelectionKind } from './FilterOption';
import type { HybridPopoverGroup, HybridPopoverItem } from './HybridPopover';

export interface FilterListProps {
  items: HybridPopoverItem[] | HybridPopoverGroup[];
  isGrouped: boolean;
  selection: FilterOptionSelectionKind;
  draftValue: string[] | string | null;
  enableReorder: boolean;
  hasGlobalSelectAll: boolean;
  hasAnyDragHandle: boolean;
  radioName?: string;
  ariaLabel?: string;
  onToggleItem: (item: HybridPopoverItem) => void;
  onToggleGroupSelectAll?: (group: HybridPopoverGroup) => void;
  onToggleGlobalSelectAll?: () => void;
  onInline?: (item: HybridPopoverItem) => void;
}

interface SelectAllState {
  isChecked: boolean;
  isIndeterminate: boolean;
  isDisabled: boolean;
}

function computeSelectAllState(
  items: HybridPopoverItem[],
  draft: string[],
): SelectAllState {
  const enabled = items.filter((i) => !i.isDisabled);
  if (enabled.length === 0) {
    return { isChecked: false, isIndeterminate: false, isDisabled: true };
  }
  const draftSet = new Set(draft);
  const selectedCount = enabled.filter((i) => draftSet.has(i.id)).length;
  return {
    isChecked: selectedCount === enabled.length,
    isIndeterminate: selectedCount > 0 && selectedCount < enabled.length,
    isDisabled: false,
  };
}

const FilterList = forwardRef<HTMLDivElement, FilterListProps>(
  function FilterList(
    {
      items,
      isGrouped,
      selection,
      draftValue,
      enableReorder,
      hasGlobalSelectAll,
      hasAnyDragHandle,
      radioName,
      ariaLabel,
      onToggleItem,
      onToggleGroupSelectAll,
      onToggleGlobalSelectAll,
      onInline,
    },
    ref,
  ) {
    const isMulti = selection === 'multi';

    // Combine the consumer's forwarded ref with our local ref so we can
    // strip the native checkbox __input from the tab order on every render.
    // The list-level roving owns the single tab stop.
    const localListRef = useRef<HTMLDivElement | null>(null);
    const setListRef = (node: HTMLDivElement | null) => {
      localListRef.current = node;
      if (typeof ref === 'function') ref(node);
      else if (ref) (ref as { current: HTMLDivElement | null }).current = node;
    };

    useEffect(() => {
      const list = localListRef.current;
      if (!list) return;
      list
        .querySelectorAll<HTMLInputElement>(
          '.arvo-hpop__sa .arvo-checkbox__input',
        )
        .forEach((input) => {
          input.tabIndex = -1;
        });
    });

    const draftArray = useMemo<string[]>(
      () =>
        isMulti
          ? Array.isArray(draftValue)
            ? draftValue
            : []
          : [],
      [isMulti, draftValue],
    );

    const draftSingle = !isMulti && typeof draftValue === 'string' ? draftValue : null;

    const isItemChecked = (item: HybridPopoverItem) => {
      if (selection === 'none') return false;
      if (isMulti) return draftArray.includes(item.id);
      return draftSingle === item.id;
    };

    const renderRow = (item: HybridPopoverItem, groupId: string | null, draggable: boolean) => (
      <FilterOption
        key={item.id}
        item={item}
        selection={selection}
        isChecked={isItemChecked(item)}
        hasAnyDragHandle={hasAnyDragHandle}
        isDraggable={draggable}
        groupId={groupId}
        radioName={radioName}
        onToggle={onToggleItem}
        onInline={onInline}
      />
    );

    const flatItems = useMemo<HybridPopoverItem[]>(
      () =>
        isGrouped
          ? (items as HybridPopoverGroup[]).flatMap((g) => g.items)
          : (items as HybridPopoverItem[]),
      [items, isGrouped],
    );

    const globalSelectAll =
      isMulti && hasGlobalSelectAll
        ? computeSelectAllState(flatItems, draftArray)
        : null;

    // Listbox/group role + aria-multiselectable per ARIA APG. The roving
    // tabindex itself is wired by HybridPopover via createTabRoving.
    const listRole =
      selection === 'none' ? 'group' : 'listbox';

    return (
      <div
        ref={setListRef}
        className="arvo-hpop__list"
        role={listRole}
        aria-label={ariaLabel ?? 'Filter options'}
        aria-multiselectable={isMulti ? true : undefined}
      >
        {globalSelectAll && (
          <div
            className="arvo-hpop__sa"
            role="option"
            tabIndex={-1}
            aria-selected={globalSelectAll.isChecked}
            aria-disabled={globalSelectAll.isDisabled || undefined}
            data-sa="global"
            onKeyDown={(event) => {
              if (event.key !== ' ' && event.key !== 'Enter') return;
              if (globalSelectAll.isDisabled) return;
              event.preventDefault();
              onToggleGlobalSelectAll?.();
            }}
          >
            <ArvoCheckbox
              size="sm"
              isChecked={globalSelectAll.isChecked}
              isIndeterminate={globalSelectAll.isIndeterminate}
              isDisabled={globalSelectAll.isDisabled}
              onChange={() => onToggleGlobalSelectAll?.()}
              aria-label="Select all"
            />
            <span
              className="arvo-hpop__sa__lbl"
              onClick={() => {
                if (globalSelectAll.isDisabled) return;
                onToggleGlobalSelectAll?.();
              }}
            >
              Select all
            </span>
          </div>
        )}

        {isGrouped
          ? (items as HybridPopoverGroup[]).map((group, gi) => {
              const groupDraggable = enableReorder && group.isDraggable !== false;
              const groupSA =
                isMulti && group.hasSelectAll
                  ? computeSelectAllState(group.items, draftArray)
                  : null;
              return (
                <div key={group.id} className="arvo-hpop__grp" data-group={group.id}>
                  {gi > 0 && <div className="arvo-hpop__divider" role="separator" />}
                  {group.label && (
                    <div className="arvo-hpop__grp-hdr">{group.label}</div>
                  )}
                  {groupSA && (
                    <div
                      className="arvo-hpop__sa arvo-hpop__sa--group"
                      role="option"
                      tabIndex={-1}
                      aria-selected={groupSA.isChecked}
                      aria-disabled={groupSA.isDisabled || undefined}
                      data-sa={`group:${group.id}`}
                      onKeyDown={(event) => {
                        if (event.key !== ' ' && event.key !== 'Enter') return;
                        if (groupSA.isDisabled) return;
                        event.preventDefault();
                        onToggleGroupSelectAll?.(group);
                      }}
                    >
                      <ArvoCheckbox
                        size="sm"
                        isChecked={groupSA.isChecked}
                        isIndeterminate={groupSA.isIndeterminate}
                        isDisabled={groupSA.isDisabled}
                        onChange={() => onToggleGroupSelectAll?.(group)}
                        aria-label={`Select all ${group.label ?? group.id}`}
                      />
                      <span
                        className="arvo-hpop__sa__lbl"
                        onClick={() => {
                          if (groupSA.isDisabled) return;
                          onToggleGroupSelectAll?.(group);
                        }}
                      >
                        {`Select all ${group.label ?? ''}`.trim()}
                      </span>
                    </div>
                  )}
                  {group.items.map((item) => {
                    const itemDraggable =
                      groupDraggable && item.isDraggable !== false;
                    return renderRow(item, group.id, itemDraggable);
                  })}
                </div>
              );
            })
          : (items as HybridPopoverItem[]).map((item) => {
              const itemDraggable =
                enableReorder && item.isDraggable !== false;
              return renderRow(item, null, itemDraggable);
            })}
      </div>
    );
  },
);

FilterList.displayName = 'ArvoHybridPopoverFilterList';

export default FilterList;
